import React from "react";
import SearchIcon from "@mui/icons-material/Search";

const GptSearcBar = () => {
  const handleSubmit = (e) => {
    e.preventDefault();
  };
  return (
    <div>
      <div className="w-full h-full pt-40  relative z-40 ">
        <form
          onSubmit={handleSubmit}
          className="w-2/6 m-auto rounded-sm flex place-items-center bg-white shadow"
        >
          <input
            type="text"
            name="search"
            placeholder="Search for Movies, TvShows & more"
            className="w-full p-3 outline-none"
          />
          <button className="bg-red-800 text-white py-3 px-4">
            <SearchIcon />
          </button>
        </form>
      </div>
    </div>
  );
};

export default GptSearcBar;
